/// <summary>Handles receipt recording.</summary>
public sealed class RecordReceiptHandler(IInventoryLedger ledger, TimeProvider timeProvider)
    : IRequestHandler<RecordReceiptCommand, InventoryMovementResponse?>
{
    /// <inheritdoc />
